import { describe, expect, test } from '@a0n/gnosis/test';
import {
  formatUntanglingActionLabel,
  recommendUntanglingStrategy,
} from './untangling-strategy';

describe('untangling strategy', () => {
  test('holds when the knot is already an unknot', () => {
    const recommendation = recommendUntanglingStrategy({ crossingNumber: 0 });

    expect(recommendation.action).toBe('hold');
    expect(recommendation.culpritLikely).toBe(false);
  });

  test('prefers direct simplification for shallow removable knots', () => {
    const recommendation = recommendUntanglingStrategy({
      crossingNumber: 2,
      beta1: 1,
    });

    expect(recommendation.action).toBe('direct-simplify');
  });

  test('prefers staged expansion for composite high-unknotting knots', () => {
    const recommendation = recommendUntanglingStrategy({
      crossingNumber: 11,
      beta1: 2,
      violationPaths: 3,
      defectFamily: 'composite',
    });

    expect(recommendation.action).toBe('staged-expand-first');
    expect(recommendation.culpritLikely).toBe(true);
    expect(recommendation.supportingTheorems).toContain('THM-S7-STAGGER');
  });

  test('minimizes within class when beta1 consumes the knot', () => {
    const recommendation = recommendUntanglingStrategy({
      crossingNumber: 4,
      beta1: 4,
    });

    expect(recommendation.action).toBe('minimize-within-class');
    expect(recommendation.supportingTheorems).toContain(
      'THM-HYPERBOLIC-HAS-MINIMUM'
    );
  });

  test('formats user-facing labels', () => {
    expect(formatUntanglingActionLabel('staged-expand-first')).toBe(
      'staged expand first'
    );
  });
});
